namespace sv_f07e0bf7a0dc436694e4a8e9cc010ee0.Client.Auth;

public sealed class UserInfo
{
    public required string Email { get; init; }
    public required string[] Roles { get; init; }
}

using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;

namespace sv_f07e0bf7a0dc436694e4a8e9cc010ee0.Client.Auth;

/// <summary>
/// Client-side (WebAssembly) AuthenticationStateProvider that reads
/// the user info persisted by the server during prerendering.
/// </summary>
public sealed class PersistentAuthenticationStateProvider : AuthenticationStateProvider
{
    private static readonly Task<AuthenticationState> _unauthenticated =
        Task.FromResult(new AuthenticationState(new ClaimsPrincipal(new ClaimsIdentity())));

    private readonly Task<AuthenticationState> _authState;

    public PersistentAuthenticationStateProvider(PersistentComponentState persistentState)
    {
        if (persistentState.TryTakeFromJson<UserInfo>(nameof(UserInfo), out var userInfo) && userInfo is not null)
        {
            _authState = Task.FromResult(new AuthenticationState(CreateClaimsPrincipal(userInfo)));
        }
        else
        {
            _authState = _unauthenticated;
        }
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync() => _authState;

    private static ClaimsPrincipal CreateClaimsPrincipal(UserInfo userInfo)
    {
        var claims = new List<Claim>
        {
            new(ClaimTypes.Name, userInfo.Email),
            new(ClaimTypes.Email, userInfo.Email),
        };

        foreach (var role in userInfo.Roles)
        {
            claims.Add(new Claim(ClaimTypes.Role, role));
        }

        return new ClaimsPrincipal(new ClaimsIdentity(claims, authenticationType: "Hardcoded"));
    }
}

using System.Security.Claims;
using Microsoft.AspNetCore.Components.Authorization;

namespace sv_f07e0bf7a0dc436694e4a8e9cc010ee0.Auth;

/// <summary>
/// Server-side AuthenticationStateProvider that always returns a
/// hardcoded authenticated user (bob@example.com) with roles User and Editor.
/// </summary>
public sealed class HardcodedAuthenticationStateProvider : AuthenticationStateProvider
{
    private static readonly Task<AuthenticationState> _authState = Task.FromResult(CreateState());

    public override Task<AuthenticationState> GetAuthenticationStateAsync() => _authState;

    private static AuthenticationState CreateState()
    {
        var claims = new[]
        {
            new Claim(ClaimTypes.Name, "bob@example.com"),
            new Claim(ClaimTypes.Email, "bob@example.com"),
            new Claim(ClaimTypes.Role, "User"),
            new Claim(ClaimTypes.Role, "Editor"),
        };

        var identity = new ClaimsIdentity(claims, authenticationType: "Hardcoded");
        return new AuthenticationState(new ClaimsPrincipal(identity));
    }
}

using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;
using Microsoft.AspNetCore.Components.Web;
using sv_f07e0bf7a0dc436694e4a8e9cc010ee0.Client.Auth;

namespace sv_f07e0bf7a0dc436694e4a8e9cc010ee0.Auth;

/// <summary>
/// Subscribes to the server-side AuthenticationStateProvider and
/// persists user info into PersistentComponentState so the WASM
/// client can reconstruct the ClaimsPrincipal after it activates.
/// </summary>
public sealed class PersistingAuthenticationStateProvider : IHostEnvironmentAuthenticationStateProvider, IDisposable
{
    private readonly PersistentComponentState _persistentState;
    private readonly AuthenticationStateProvider _authStateProvider;
    private PersistingComponentStateSubscription _subscription;
    private Task<AuthenticationState>? _authenticationStateTask;

    public PersistingAuthenticationStateProvider(
        PersistentComponentState persistentState,
        AuthenticationStateProvider authStateProvider)
    {
        _persistentState = persistentState;
        _authStateProvider = authStateProvider;

        AuthenticationStateChanged(authStateProvider.GetAuthenticationStateAsync());
        _authStateProvider.AuthenticationStateChanged += AuthenticationStateChanged;
        _subscription = _persistentState.RegisterOnPersisting(OnPersistingAsync, RenderMode.InteractiveWebAssembly);
    }

    public void SetAuthenticationState(Task<AuthenticationState> authenticationStateTask)
    {
        _authenticationStateTask = authenticationStateTask;
    }

    private void AuthenticationStateChanged(Task<AuthenticationState> task)
    {
        _authenticationStateTask = task;
    }

    private async Task OnPersistingAsync()
    {
        var authState = await (_authenticationStateTask ?? _authStateProvider.GetAuthenticationStateAsync());
        var principal = authState.User;

        if (principal.Identity?.IsAuthenticated == true)
        {
            var userInfo = new UserInfo
            {
                Email = principal.FindFirstValue(ClaimTypes.Email) ?? principal.Identity.Name ?? "",
                Roles = principal.FindAll(ClaimTypes.Role).Select(c => c.Value).ToArray(),
            };

            _persistentState.PersistAsJson(nameof(UserInfo), userInfo);
        }
    }

    public void Dispose()
    {
        _subscription.Dispose();
        _authStateProvider.AuthenticationStateChanged -= AuthenticationStateChanged;
    }
}

