using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;
using Microsoft.AspNetCore.Components.Web;
using sv_f07e0bf7a0dc436694e4a8e9cc010ee0.Client.Auth;

namespace sv_f07e0bf7a0dc436694e4a8e9cc010ee0.Auth;

/// <summary>
/// Server-side AuthenticationStateProvider that always returns a
/// hardcoded authenticated user (bob@example.com) with roles User and Editor,
/// and persists the auth state so WebAssembly can pick it up.
/// </summary>
public sealed class HardcodedAuthenticationStateProvider : AuthenticationStateProvider, IDisposable
{
    private static readonly AuthenticationState _authState = CreateState();
    private readonly PersistingComponentStateSubscription _subscription;

    public HardcodedAuthenticationStateProvider(PersistentComponentState persistentState)
    {
        _subscription = persistentState.RegisterOnPersisting(() =>
        {
            var principal = _authState.User;
            var userInfo = new UserInfo
            {
                Email = principal.FindFirstValue(ClaimTypes.Email) ?? principal.Identity!.Name!,
                Roles = principal.FindAll(ClaimTypes.Role).Select(c => c.Value).ToArray(),
            };
            persistentState.PersistAsJson(nameof(UserInfo), userInfo);
            return Task.CompletedTask;
        }, RenderMode.InteractiveWebAssembly);
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync()
        => Task.FromResult(_authState);

    private static AuthenticationState CreateState()
    {
        var claims = new[]
        {
            new Claim(ClaimTypes.Name, "bob@example.com"),
            new Claim(ClaimTypes.Email, "bob@example.com"),
            new Claim(ClaimTypes.Role, "User"),
            new Claim(ClaimTypes.Role, "Editor"),
        };

        var identity = new ClaimsIdentity(claims, authenticationType: "Hardcoded");
        return new AuthenticationState(new ClaimsPrincipal(identity));
    }

    public void Dispose() => _subscription.Dispose();
}

